func TestOSExecutorExecuteInDir_NonLinuxParentDeathFallbackDocumentsGap(t *testing.T) {
	_, file, _, ok := runtime.Caller(0)
	require.True(t, ok)

	// Check that executor_unix.go documents the non-Linux limitation
	data, err := os.ReadFile(filepath.Join(filepath.Dir(file), "executor_unix.go"))
	require.NoError(t, err)
	src := string(data)
	// The file must document that Pdeathsig is Linux-only and what happens on macOS/Windows
	require.Contains(t, src, "Linux-only", "executor_unix.go must document that Pdeathsig is Linux-only")
	require.Contains(t, src, "macOS", "executor_unix.go must document fallback behavior on macOS")
	require.Contains(t, src, "Windows", "executor_unix.go must document fallback behavior on Windows")

	// Check that executor_windows.go exists and documents the fallback
	windowsFile := filepath.Join(filepath.Dir(file), "executor_windows.go")
	windowsData, err := os.ReadFile(windowsFile)
	require.NoError(t, err)
	windowsSrc := string(windowsData)
	require.Contains(t, windowsSrc, "Windows", "executor_windows.go must document platform-specific behavior")
}

